import React, { useEffect, useState } from "react";
import { register } from "../lib/api";
import RegistrationForm from "../Components/Forms/RegistrationForm";
import { useNavigate } from "react-router-dom";
import Banner from "../Components/Banner";
import { useTranslation } from "react-i18next";

const RegisterPage = () => {
  const [isRegistrationSuccess, setIsRegistrationSuccess] = useState(false);
  const [registrationMessage, setRegistrationMessage] = useState("");
  const navigate = useNavigate();
  const { t } = useTranslation();

  useEffect(() => {
    setTimeout(() => { if (isRegistrationSuccess) { setIsRegistrationSuccess(false); navigate("/login"); } }, 2000);
  }, [isRegistrationSuccess]);

  const onSubmit = (values, formikHelpers) => {
    setTimeout(() => {
      register(values)
        .then(data => { formikHelpers.resetForm(); setRegistrationMessage(t("newUserCreated", { newUser: data.userName })); setIsRegistrationSuccess(true); })
        .catch(error => formikHelpers.setFieldError("register", t("userAlreadyExists", { userName: error.message })))
        .finally(() => formikHelpers.setSubmitting(false));
    }, 1000);
  };

  return (
    <div className="ink-page page-fade-in">
      <div className="ink-form-wrap">
        <div style={{ width: "100%", maxWidth: 480 }}>
          <RegistrationForm isSubmitted={isRegistrationSuccess} onSubmit={onSubmit} />
          {isRegistrationSuccess && <Banner className="text-success border-success mt-4" message={registrationMessage} />}
        </div>
      </div>
    </div>
  );
};
export default RegisterPage;
